        vector<int> result;
        for (int i = 0; i < nums.size(); i++) {
            if (i == nums.size() - 1 || nums[i] == 0) {
                return -1;
            }
            result.push_back(nums[i] * nums[i + 1]);
        }
        return result;
    }
